'use client'
import { cn } from '@cascivo/core'
import type { CSSProperties, HTMLAttributes } from 'react'
import styles from './masonry.module.css'

type SpaceStep = 1 | 2 | 3 | 4 | 5 | 6 | 8 | 10 | 12

export interface MasonryProps extends HTMLAttributes<HTMLDivElement> {
  cols?: number
  gap?: SpaceStep
  className?: string | undefined
}

export function Masonry({ cols = 3, gap = 4, className, style, ...props }: MasonryProps) {
  return (
    <div
      className={cn(styles['masonry'], className)}
      style={{
        ['--_cols' as string]: String(cols),
        ['--_gap' as string]: `var(--cascivo-space-${gap})`,
        ...(style as CSSProperties | undefined),
      }}
      {...props}
    />
  )
}

@layer cascivo.component {
  /* Fallback: CSS multi-columns. Items flow column-major (top-to-bottom per column). */
  .masonry {
    column-count: var(--_cols, 3);
    column-gap: var(--_gap, var(--cascivo-space-4));
  }

  .masonry > * {
    break-inside: avoid;
    margin-block-end: var(--_gap, var(--cascivo-space-4));
  }

  /* Native masonry — grid-template-rows syntax (Firefox / spec baseline). */
  @supports (grid-template-rows: masonry) {
    .masonry {
      display: grid;
      column-count: initial;
      grid-template-columns: repeat(var(--_cols, 3), minmax(0, 1fr));
      grid-template-rows: masonry;
      gap: var(--_gap, var(--cascivo-space-4));
    }

    .masonry > * {
      margin-block-end: 0;
    }
  }

  /* Native masonry — display syntax (WebKit/Chrome lineage, in-flux spec). */
  @supports (display: masonry) {
    .masonry {
      display: masonry;
      column-count: initial;
      masonry-template-tracks: repeat(var(--_cols, 3), minmax(0, 1fr));
      gap: var(--_gap, var(--cascivo-space-4));
    }

    .masonry > * {
      margin-block-end: 0;
    }
  }
}
